def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 5):
                for l in range(1, 4):
                    penalty += ((ratio ** (k + l)) / (k * l + 1)) * ((-1) ** (k + l))
            priorities[i] = ratio ** 4 + penalty + np.log1p(ratio)
            if capacity < item * 0.5:
                priorities[i] *= 2
        elif 1 < ratio <= 2:
            base = 0
            for p in range(1, 7):
                base += ((-1) ** p) * (ratio ** p) / (p * 2)
            adjusted = base * (5 - (ratio))
            priorities[i] = abs(adjusted) + np.sqrt(ratio)
            if capacity % 3 == 0:
                priorities[i] += ratio / 2
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priority_val = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    extra += ((ratio ** m) / (m + 2)) * (1 if m % 2 == 0 else -0.5)
                priority_val += extra
            if capacity > item * 2:
                priority_val /= 2
            priorities[i] = priority_val
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if ratio > 0 and ratio < 1 and capacity % 5 == 0:
            sum_mod = 0
            for q in range(1, 5):
                sum_mod += ((-1) ** q) * np.sin(ratio * q * np.pi)
            priorities[i] += abs(sum_mod) * 1.5
        if priorities[i] != np.inf and priorities[i] > 100:
            retries = 0
            adjusted_priority = priorities[i]
            while adjusted_priority > 100 and retries < 5:
                adjusted_priority /= 2
                retries += 1
            priorities[i] = adjusted_priority
    return priorities
